import React, { useState, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:8080";

function formatDataHora(value) {
    if (!value) return "-";
    const d = new Date(value);
    if (isNaN(d.getTime())) return value;
    return d.toLocaleString("pt-BR", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
    });
}

function HistoricoComponent() {
    const [lista, setLista] = useState([]);
    const [loading, setLoading] = useState(true);
    const [erro, setErro] = useState(null);

    useEffect(() => {
        setLoading(true);
        axios
            .get(`${API}/historicos`)
            .then((r) => setLista(r.data || []))
            .catch(() => setErro("Erro ao carregar histórico."))
            .finally(() => setLoading(false));
    }, []);

    if (loading) return <div className="mt-3">Carregando histórico...</div>;
    if (erro) return <div className="alert alert-warning mt-3">{erro}</div>;

    return (
        <div className="historico-page">
            <h2 className="mb-4">Histórico</h2>
            <p className="text-muted mb-3">Ações realizadas no sistema (cadastros, atualizações, exclusões e trocas de status de corridas).</p>
            <div className="table-responsive">
                <table className="table table-striped table-bordered">
                    <thead className="table-dark">
                        <tr>
                            <th>Data / Hora</th>
                            <th>Tipo</th>
                            <th>Entidade</th>
                            <th>Descrição</th>
                        </tr>
                    </thead>
                    <tbody>
                        {lista.length === 0 ? (
                            <tr>
                                <td colSpan="4">Nenhum registro no histórico.</td>
                            </tr>
                        ) : (
                            lista.map((item) => (
                                <tr key={item.id}>
                                    <td>{formatDataHora(item.dataHora)}</td>
                                    <td>{item.tipoAcao ?? "-"}</td>
                                    <td>{item.entidadeAfetada ?? "-"}</td>
                                    <td>{item.descricao ?? "-"}</td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

export default HistoricoComponent;
